func UpdateInventory(ctx context.Context, sku string, qty int) error {
    // 1. Write to DB (source of truth)
    if err := db.UpdateInventory(ctx, sku, qty); err != nil {
        return err
    }
    // 2. Update cache synchronously (write-through)
    data, _ := json.Marshal(Inventory{SKU: sku, Qty: qty})
    ttl := 1*time.Hour + time.Duration(rand.Intn(600))*time.Second
    if err := rdb.Set(ctx, "inv:"+sku, data, ttl).Err(); err != nil {
        // Cache write failed: invalidate to prevent stale read
        rdb.Del(ctx, "inv:"+sku)
        log.Warn("cache write failed, invalidated", "sku", sku, "err", err)
    }
    return nil
}
